import{homedir}from"node:os";import{join}from"node:path";import{createRollingJsonlWriter,DEFAULT_LOG_ROLLING_MAX_BYTES}from"./utils/rolling-jsonl.js";import{asTrimmedNonEmptyString as asNonEmptyString}from"./utils/text.js";const DEFAULT_LOG_DIR=join(homedir(),".kimi","kimi-claw","log");export const DEFAULT_OBS_TRACE_FILE=join(DEFAULT_LOG_DIR,"openclaw_all_trace.log");export const createObsEventWriter=t=>{const o=t.filePath??DEFAULT_OBS_TRACE_FILE;if(!o.trim())return t=>{};const r=createRollingJsonlWriter({filePath:o,logger:t.logger,contextLabel:"obs",maxBytes:DEFAULT_LOG_ROLLING_MAX_BYTES});return t=>{const o={...t,ts:asNonEmptyString(t.ts)??(new Date).toISOString()};r(o)}};